// --- CRUD for Passengers ---
export const getPassengersByCompany = async (companyId: string) => {
    try {
        const q = query(passengersCollection, where("companyId", "==", companyId));
        const snapshot = await getDocs(q);
        return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Passenger));
    } catch(e) { return []; }
};

export const listenToPassengersByCompany = (companyId: string, callback: (passengers: Passenger[]) => void, onError?: (error: any) => void) => {
    // ENGINEERING FIX: We perform client-side sorting here to bypass the need for composite indexes.
    const q = query(passengersCollection, where("companyId", "==", companyId));

    return safeSnapshot(q, callback, (snapshot: any) => {
        const unsorted = snapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() } as Passenger));
        // Client-side sort by createdAt descending
        const sorted = unsorted.sort((a: Passenger, b: Passenger) => {
            const timeA = a.createdAt?.seconds || 0;
            const timeB = b.createdAt?.seconds || 0;
            return timeB - timeA;
        });
        return sorted;
    }, [], onError);
};

export const getPassengersByCompanyPaginated = async ({ companyId, limitNum, startAfterDoc }: { companyId: string, limitNum: number, startAfterDoc?: QueryDocumentSnapshot }) => {
    try {
        // Note: Pagination strictly requires Indexes. If this fails, the UI falls back to list all.
        let q = query(passengersCollection, where("companyId", "==", companyId), orderBy("createdAt", "desc"), limit(limitNum));

        if (startAfterDoc) {
            q = query(passengersCollection, where("companyId", "==", companyId), orderBy("createdAt", "desc"), startAfter(startAfterDoc), limit(limitNum));
        }

        const snapshot = await getDocs(q);
        const passengers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Passenger));
        return {
            passengers,
            lastVisible: snapshot.docs[snapshot.docs.length - 1],
            hasMore: snapshot.docs.length === limitNum
        };
    } catch (e) {
        console.error("Pagination fetch failed, likely due to missing index. Fallback recommended.", e);
        throw e; 
    }
};

export const listenToAllPassengers = (callback: (passengers: Passenger[]) => void, onError?: (error: any) => void) => {
    // ENGINEERING FIX: Perform client-side sorting to avoid any potential index issues during development.
    const q = query(passengersCollection);
    return safeSnapshot(q, callback, (snapshot: any) => {
        const unsorted = snapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() } as Passenger));

        // IMPORTANT SECURITY/UX FIX: Filter out guest demo data for standard listeners
        // This ensures main admins don't see fake data unless they are in specific demo modes.
        const filtered = unsorted.filter((p: Passenger) => 
            p.companyId !== 'guest-demo' && 
            p.companyId !== 'guest-demo-spie' && 
            p.companyId !== 'guest-demo-modec'
        );

        const sorted = filtered.sort((a: Passenger, b: Passenger) => {
            const timeA = a.createdAt?.seconds || 0;
            const timeB = b.createdAt?.seconds || 0;
            return timeB - timeA;
        });
        return sorted;
    }, [], onError);
};

// --- NEW SMART LISTENER ---
// This function determines the appropriate query based on the user's role to prevent permission errors.
export const listenToAccessiblePassengers = (user: User & UserSettings, callback: (passengers: Passenger[]) => void, onError?: (error: any) => void) => {
    if (!user) {
        callback([]);
        return () => {};
    }

    // 1. GUEST USER: Strictly limited to guest-demo data
    if (user.username === 'guest') {
        console.log(`[Streamline] Guest User: Fetching specific guest-demo data only.`);
        return listenToPassengersByCompany('guest-demo', callback, onError);
    }

    // 2. CLIENT USER: Strictly limited to their own company
    if (user.role === 'client') {
        if (user.companyId) {
            console.log(`[Streamline] Restricted mode: Fetching only for company ${user.companyId}`);
            return listenToPassengersByCompany(user.companyId, callback, onError);
        } else {
            console.warn('[Streamline] Client user missing companyId. Aborting fetch to prevent permission error.');
            // Return dummy unsubscribe function
            callback([]); // Pass empty array so UI updates
            return () => {}; 
        }
    } 

    // 3. ADMIN DEMO SANDBOX LOGIC
    if (user.username === 'admindemo') {
        console.log(`[Streamline] Admin Demo Sandbox: Fetching only guest data.`);
        const guestCompanyIds = ['guest-demo', 'guest-demo-spie', 'guest-demo-modec'];
        const q = query(passengersCollection, where("companyId", "in", guestCompanyIds));

        return safeSnapshot(q, callback, (snapshot: any) => {
            const unsorted = snapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() } as Passenger));
            return unsorted.sort((a: Passenger, b: Passenger) => {
                const timeA = a.createdAt?.seconds || 0;
                const timeB = b.createdAt?.seconds || 0;
                return timeB - timeA;
            });
        }, [], onError);
    }

    // 4. MAIN ADMIN/OFFICER: Fetch all, but the 'listenToAllPassengers' function now automatically filters out guest data.
    console.log(`[Streamline] Global mode: Fetching all passengers for ${user.role} (Guest data filtered out)`);
    return listenToAllPassengers(callback, onError);
};

