export const listenToUsersAndSettings = (callback: (users: (User & UserSettings)[]) => void) => {
    return onSnapshot(usersCollection, async (userSnapshot) => {
        try {
            if (auth.currentUser?.displayName === 'admindemo') {
                 const allowedUsers = ['admindemo', 'guest'];
                 const filteredDocs = userSnapshot.docs.filter(doc => allowedUsers.includes(doc.id));

                 const settingsSnapshot = await getDocs(userSettingsCollection);
                 const settingsMap = new Map<string, UserSettings>(settingsSnapshot.docs.map(d => [d.id, d.data() as UserSettings]));

                 const merged = filteredDocs.map(doc => {
                    const u = { username: doc.id, ...doc.data() } as User;
                    const s = settingsMap.get(u.username);
                    return { 
                        ...u, 
                        ...(s || {}), 
                        id: u.username, 
                        isActive: s?.isActive ?? (u.role === 'admin'),
                        disabledMenus: s?.disabledMenus ?? [] 
                    } as User & UserSettings;
                 });

                 callback(merged);
                 return;
            }

            const users = userSnapshot.docs.map(doc => ({ username: doc.id, ...doc.data() } as User));
            const settingsSnapshot = await getDocs(userSettingsCollection);
            const settingsMap = new Map<string, UserSettings>(settingsSnapshot.docs.map(d => [d.id, d.data() as UserSettings]));

            const merged = users.map(u => {
                const s = settingsMap.get(u.username);
                return { 
                    ...u, 
                    ...(s || {}), 
                    id: u.username, 
                    isActive: s?.isActive ?? (u.role === 'admin'),
                    disabledMenus: s?.disabledMenus ?? [] 
                } as User & UserSettings;
            });
            callback(merged);
        } catch (error: any) {
            console.warn("Permission denied reading users/settings (dev mode fallback).");
            callback([]);
        }
    }, (error) => {
        console.warn("Permission denied reading users collection (dev mode fallback).");
        callback([]);
    });
};

// Client-Side User Creation for Training Demo
export const createNewUserClientSide = async (username: string, password: string, role: UserRole, email: string, contactInfo: any, companyId?: string) => {
    // 1. Create a secondary app instance to create the user without logging out the admin
    const secondaryApp = initializeApp(firebaseConfig, "Secondary");
    const secondaryAuth = getAuth(secondaryApp);

    let uid = '';

    try {
        const userCredential = await createUserWithEmailAndPassword(secondaryAuth, email, password);
        uid = userCredential.user.uid;

        // 2. Update profile on the new user
        await updateProfile(userCredential.user, { displayName: username });

        // 3. Write to Firestore using the PRIMARY app (admin's auth)
        // We write the data needed for the app to recognize this user
        const batch = writeBatch(db);

        const userRef = doc(db, 'users', username);
        batch.set(userRef, {
            role: role,
            email: email.toLowerCase(),
            uid: uid,
            createdAt: serverTimestamp()
        });

        const userSettingsRef = doc(db, 'users_settings', username);
        const settingsData: any = {
            id: username,
            uid: uid,
            email: email.toLowerCase(),
            isActive: true,
            disabledMenus: [],
            layout: 'default',
            firstNames: contactInfo?.firstNames || '',
            surname: contactInfo?.surname || '',
            phone: contactInfo?.phone || '',
            createdAt: serverTimestamp()
        };

        if (companyId) {
            settingsData.companyId = companyId;
        }

        batch.set(userSettingsRef, settingsData);

        await batch.commit();

        // 4. Cleanup
        await signOut(secondaryAuth);
        await deleteApp(secondaryApp);

        return { success: true, uid };

    } catch (error) {
        // Cleanup if error
        await deleteApp(secondaryApp);
        throw error;
    }
};

