// --- Initial User Seeding ---
export const seedInitialUsers = async () => {
    const SESSION_SEED_FLAG = 'seed_run_this_session_v66'; // Bumped version for clean start

    if (sessionStorage.getItem(SESSION_SEED_FLAG)) {
        return;
    }

    console.log(`Running initial user seed (client-side): ${SESSION_SEED_FLAG}`);

    for (const user of DEFAULT_USERS) {
        let uid = '';

        try {
            const userCredential = await createUserWithEmailAndPassword(auth, user.email, user.password);
            uid = userCredential.user.uid;
            console.log(`Created auth user for ${user.username}.`);
        } catch (error: any) {
            if (error.code === 'auth/email-already-in-use') {
                try {
                    const userCredential = await signInWithEmailAndPassword(auth, user.email, user.password);
                    uid = userCredential.user.uid;
                } catch (loginErr) {
                    console.error(`Could not sign in to repair ${user.username}:`, loginErr);
                }
            } else {
                console.error(`Failed to seed user '${user.username}'. Error:`, error);
            }
        }

        if (uid) {
            try {
                console.log(`Ensuring Firestore docs exist for user: ${user.username}...`);

                if (auth.currentUser && auth.currentUser.uid === uid) {
                     await updateProfile(auth.currentUser, { displayName: user.username }).catch(() => {});
                }

                const batch = writeBatch(db);
                const userRef = doc(db, 'users', user.username);

                const userData: any = {
                    role: user.role,
                    email: user.email.toLowerCase(),
                    uid: uid,
                };

                batch.set(userRef, userData, { merge: true });

                const userSettingsRef = doc(db, 'users_settings', user.username);

                const settingsData: any = {
                    isActive: true,
                    email: user.email.toLowerCase(),
                    uid: uid,
                    disabledMenus: [],
                    layout: 'default'
                };

                batch.set(userSettingsRef, settingsData, { merge: true });

                await batch.commit();
                console.log(`User ${user.username} seeded/repaired successfully.`);
            } catch (dbError: any) {
                if (dbError.code === 'permission-denied') {
                    console.warn(`Permission denied while seeding ${user.username}. Skipping...`);
                } else {
                    console.error(`Failed to write Firestore data for ${user.username}:`, dbError);
                }
            }
        }
    }

    if (auth.currentUser) {
        console.log("Seeding complete. Ensuring clean state by signing out any temporary session.");
        await signOut(auth);
    }

    sessionStorage.setItem(SESSION_SEED_FLAG, 'true');
};

