export const restoreFromBackup = async (data: any) => {
    const batchLimit = 500;
    let batch = writeBatch(db);
    let count = 0;

    const collections: Record<string, any[]> = {
        'users': data.users,
        'users_settings': data.usersSettings,
        'passengers': data.passengers,
        'checklists': data.checklists,
        'settings': data.settings
    };

    for (const [colName, docs] of Object.entries(collections)) {
        if (!docs) continue;
        for (const docData of docs) {
            let docRef;
            if (colName === 'settings') {
                docRef = doc(db, colName, docData.id);
                const { id, ...rest } = docData;
                batch.set(docRef, rest);
            } else if (colName === 'users' || colName === 'users_settings') {
                const id = docData.username || docData.id; 
                if (id) {
                    docRef = doc(db, colName, id);
                    batch.set(docRef, docData);
                }
            } else {
                if (docData.id) {
                    docRef = doc(db, colName, docData.id);
                    batch.set(docRef, docData);
                } else {
                    docRef = doc(collection(db, colName));
                    batch.set(docRef, docData);
                }
            }

            count++;
            if (count >= batchLimit) {
                await batch.commit();
                batch = writeBatch(db);
                count = 0;
            }
        }
    }
    if (count > 0) {
        await batch.commit();
    }
};

