const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<(User & UserSettings) | null>(null);
  const [viewingAsUser, setViewingAsUser] = useState<(User & UserSettings) | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);
  const [showSplash, setShowSplash] = useState(true);

  useEffect(() => {
    // Enforce splash screen for at least 2.5 seconds
    const splashTimer = setTimeout(() => {
        setShowSplash(false);
    }, 2500);

    let authUnsubscribe: (() => void) | undefined;
    let settingsUnsubscribe: (() => void) | undefined;

    const initialize = async () => {
        await seedInitialUsers();

        authUnsubscribe = onAuthUserChanged(async (authUser) => {
            if (settingsUnsubscribe) {
                settingsUnsubscribe();
                settingsUnsubscribe = undefined;
            }

            if (authUser && authUser.email) {
                const normalizedEmail = authUser.email.toLowerCase();
                const usersQuery = query(collection(db, "users"), where("email", "==", normalizedEmail), limit(1));

                try {
                    const userDocSnapshot = await getDocs(usersQuery);

                    if (!userDocSnapshot.empty) {
                        const userDoc = userDocSnapshot.docs[0];
                        const username = userDoc.id;
                        const role = userDoc.data().role as UserRole;

                        // SELF-HEALING FIX: Update displayName if missing
                        if (authUser.displayName !== username) {
                            try {
                                console.log(`Self-healing: Updating Auth displayName from '${authUser.displayName}' to '${username}'`);
                                await updateProfile(authUser, { displayName: username });
                                await authUser.getIdToken(true);
                            } catch (healError) {
                                console.error("Self-healing failed, continuing anyway:", healError);
                            }
                        }

                        const settingsDocRef = doc(db, 'users_settings', username);
                        settingsUnsubscribe = onSnapshot(settingsDocRef, (settingsDoc) => {
                            const newRawSettings = (settingsDoc.exists() 
                                ? { id: settingsDoc.id, ...settingsDoc.data() } 
                                : { id: username, isActive: false, disabledMenus: [] }) as UserSettings;

                            // STRICT REPAIR: Ensure client user has correct companyId link
                            if (role === 'client' || username.startsWith('client-')) {
                                let derivedCompanyId = newRawSettings.companyId;

                                // Attempt to derive if missing
                                if (!derivedCompanyId) {
                                    const parts = username.split('-');
                                    if (parts.length > 1) {
                                        derivedCompanyId = parts[1];
                                    } else {
                                        derivedCompanyId = 'spie';
                                    }
                                }

                                if (derivedCompanyId && newRawSettings.companyId !== derivedCompanyId) {
                                    console.log(`Repairing companyId for ${username}. Setting to: ${derivedCompanyId}`);
                                    updateUserSettings(username, { companyId: derivedCompanyId });
                                    newRawSettings.companyId = derivedCompanyId;
                                }
                            }

                            const isProtectedRole = role === 'developer' || role === 'app_manager' || role === 'admin' || role === 'client' || role === 'designer' || role === 'dashboard_only';
                            const newEffectiveSettings = isProtectedRole ? { ...newRawSettings, isActive: true } : newRawSettings;

                            if (!newEffectiveSettings.isActive && !isProtectedRole) {
                                console.log('Deactivated user tried to log in. Forcing sign out.');
                                signOutUser();
                            } else {
                                setCurrentUser(prevUser => {
                                    if (!prevUser) {
                                        return { username, role, ...newEffectiveSettings };
                                    }
                                    // Deep compare critical fields
                                    if (
                                        prevUser.isActive !== newEffectiveSettings.isActive ||
                                        prevUser.layout !== newEffectiveSettings.layout ||
                                        prevUser.companyId !== newEffectiveSettings.companyId || 
                                        JSON.stringify(prevUser.disabledMenus) !== JSON.stringify(newEffectiveSettings.disabledMenus || [])
                                    ) {
                                        return { username, role, ...newEffectiveSettings };
                                    }
                                    return prevUser;
                                });
                            }
                        }, async (error) => {
                            console.error("Error listening to user settings:", error);
                            if (error.code === 'permission-denied') {
                                console.warn(`Permission denied for ${username}. Attempting JIT repair of settings...`);
                            }
                        });

                    } else {
                        // CRITICAL FIX: JIT Repair for Default Users
                        const defaultUserConfig = DEFAULT_USERS.find(u => u.email.toLowerCase() === normalizedEmail);
                        if (defaultUserConfig) {
                             console.warn(`User '${defaultUserConfig.username}' authenticated but document missing. Performing JIT repair...`);
                        } else {
                             console.error("Authenticated user not found in Firestore database and is not a default user.", authUser.email);
                             await signOutUser();
                        }
                    }
                } catch (err) {
                    console.error("Error fetching user data during init:", err);
                }
            } else {
                setCurrentUser(null);
                setViewingAsUser(null);
            }
            setIsInitializing(false);
        });
    };

    initialize();

    return () => {
        if (authUnsubscribe) authUnsubscribe();
        if (settingsUnsubscribe) settingsUnsubscribe();
        clearTimeout(splashTimer);
    };
  }, []);


  // Heartbeat for online presence
  useEffect(() => {
    if (!currentUser) return;
    const updateUserPresence = () => updateUserSettings(currentUser.username, { lastSeen: new Date() });
    updateUserPresence(); 
    const intervalId = setInterval(updateUserPresence, 60 * 1000);
    const handleVisibilityChange = () => { if (document.visibilityState === 'visible') updateUserPresence(); };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => {
        clearInterval(intervalId);
        document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [currentUser]);

  const handleLogout = async () => {
    if (currentUser) await addActivityLog(currentUser.username, 'User logged out.');
    await signOutUser();
  };

  const handleLoginAs = (userToViewAs: User & UserSettings) => {
    if (currentUser?.role === 'developer' || currentUser?.role === 'app_manager') {
        addActivityLog(currentUser.username, `Started viewing as ${userToViewAs.username}.`);
        setViewingAsUser(userToViewAs);
    }
  };

  const handleStopViewingAs = () => {
     if ((currentUser?.role === 'developer' || currentUser?.role === 'app_manager') && viewingAsUser) {
        addActivityLog(currentUser.username, `Stopped viewing as ${viewingAsUser.username}.`);
        setViewingAsUser(null);
     }
  };

  const effectiveUser = viewingAsUser || currentUser;

  // Show Splash Screen if initializing OR if timer hasn't finished
  if (isInitializing || showSplash) {
      return <SplashScreen />;
  }

  if (!currentUser) {
      return <LoginScreen />;
  }

  const renderApp = () => {
      // 1. ROOT ADMIN/DEV
      if ((currentUser.role === 'developer' || currentUser.role === 'app_manager') && !viewingAsUser) {
          return <RootApp currentUser={currentUser} onLogout={handleLogout} onLoginAs={handleLoginAs} />;
      }

      // 2. DASHBOARD ONLY MODE
      if (effectiveUser?.role === 'dashboard_only') {
          return <HeadsUpLayout currentUser={effectiveUser} onLogout={handleLogout} />;
      }

      // 3. MAIN APP LOGIC
      if (effectiveUser) {
          const themeStorageKey = (effectiveUser.role === 'developer' || effectiveUser.role === 'app_manager' || effectiveUser.role === 'designer') ? 'developerTheme' : 'theme';

          const AppToRender = () => {
            // Client portal
            if (effectiveUser.role === 'client') {
                return <ClientApp currentUser={effectiveUser} onLogout={handleLogout} />;
            }
            // Standard internal app (Admins, Officers)
            return (
                <div className="flex flex-col h-screen">
                    <MainApp 
                        currentUser={effectiveUser}
                        onLogout={handleLogout}
                    />
                </div>
            );
          };

          return (
            <ThemeProvider storageKey={themeStorageKey} userLayout={effectiveUser.layout}>
                <LayoutProvider userLayout={effectiveUser.layout}>
                    <AppToRender />
                </LayoutProvider>
            </ThemeProvider>
          );
      }
      return <LoginScreen />;
  }

  return (
      <>
        {renderApp()}
        {viewingAsUser && (
            <ViewingAsBanner user={viewingAsUser} onStop={handleStopViewingAs} />
        )}
        {currentUser.role === 'developer' && <DeveloperChat />}
      </>
  );
};

