// --- Helper: Batch Delete Collection ---
const deleteCollectionBatch = async (collectionRef: any, batchSize: number = 500) => {
    const q = query(collectionRef, limit(batchSize));
    return new Promise((resolve, reject) => {
        deleteQueryBatch(db, q, resolve).catch(reject);
    });
};

async function deleteQueryBatch(db: any, query: any, resolve: any) {
  const snapshot = await getDocs(query);

  const batchSize = snapshot.size;
  if (batchSize === 0) {
    // When there are no documents left, we are done
    resolve();
    return;
  }

  const batch = writeBatch(db);
  snapshot.docs.forEach((doc: any) => {
    batch.delete(doc.ref);
  });
  await batch.commit();

  // Recurse on the next tick, to avoid
  // exploding the stack.
  setTimeout(() => {
    deleteQueryBatch(db, query, resolve);
  }, 0);
}

