export const BatchTicketUploadModal: React.FC<BatchTicketUploadModalProps> = ({ isOpen, onClose, allPassengers, onSuccess }) => {
    const [step, setStep] = useState<'upload' | 'processing' | 'review' | 'saving'>('upload');
    const [extractedData, setExtractedData] = useState<MatchedFlightData[]>([]);
    const [processingError, setProcessingError] = useState<string | null>(null);

    // Reset state on open
    useEffect(() => {
        if (isOpen) {
            setStep('upload');
            setExtractedData([]);
            setProcessingError(null);
        }
    }, [isOpen]);

    const handleFileUpload = async (payload: { file: File, dataUrl: string }) => {
        setStep('processing');
        setProcessingError(null);

        try {
            // Prepare lightweight list for AI context
            const roster = allPassengers.map(p => ({
                id: p.id,
                name: `${p.passportData.firstNames} ${p.passportData.surname}`
            }));

            const base64 = payload.dataUrl.split(',')[1];
            const results = await extractBatchFlightData(base64, payload.file.type, roster);

            setExtractedData(results);
            setStep('review');
        } catch (error: any) {
            console.error(error);
            setProcessingError(error.message || "Failed to process document.");
            setStep('upload');
        }
    };

    const handleMatchChange = (index: number, newId: string) => {
        const newData = [...extractedData];
        newData[index].matchedPassengerId = newId;
        setExtractedData(newData);
    };

    const handleRemoveItem = (index: number) => {
        setExtractedData(prev => prev.filter((_, i) => i !== index));
    };

    const handleCommit = async () => {
        setStep('saving');
        try {
            const updates = extractedData.filter(item => item.matchedPassengerId);

            // Group tickets by passenger ID to minimize writes
            const passengerUpdates: { [key: string]: TicketData[] } = {};

            for (const item of updates) {
                if (!item.matchedPassengerId) continue;

                const pid = item.matchedPassengerId;
                if (!passengerUpdates[pid]) {
                    // Start with existing tickets
                    const p = allPassengers.find(p => p.id === pid);
                    passengerUpdates[pid] = p ? [...p.tickets] : [];
                }

                // Add new ticket
                const newTicket: TicketData = {
                    id: Date.now().toString() + Math.random().toString(36).substr(2, 5),
                    ticketNumber: item.ticketData.ticketNumber || '',
                    airline: item.ticketData.airline || '',
                    departureCity: item.ticketData.departureCity || '',
                    arrivalCity: item.ticketData.arrivalCity || '',
                    travelDate: item.ticketData.travelDate || '',
                    travelTime: item.ticketData.travelTime || '',
                    status: 'Issued'
                };
                passengerUpdates[pid].push(newTicket);
            }

            // Execute updates
            const promises = Object.entries(passengerUpdates).map(([pid, tickets]) => 
                updatePassenger(pid, { tickets })
            );

            await Promise.all(promises);
            onSuccess();
            onClose();

        } catch (error) {
            console.error("Save failed", error);
            setProcessingError("Failed to save data to database.");
            setStep('review');
        }
    };

    const renderUploadStep = () => (
        <div className="flex flex-col items-center justify-center h-full space-y-6">
            <div className="text-center max-w-lg">
                <h4 className="text-lg font-semibold text-text-primary mb-2">Upload Flight Manifest</h4>
                <p className="text-text-secondary">
                    Upload an image or PDF containing a list of flight tickets. The AI will extract flight details and automatically match them to your personnel list.
                </p>
            </div>
            <div className="w-full max-w-xl">
                <FileUploader 
                    label="Upload Ticket List (PDF/Image)" 
                    onFileUpload={handleFileUpload} 
                />
            </div>
            {processingError && (
                <div className="text-danger bg-danger/10 p-3 rounded-md mt-4">
                    {processingError}
                </div>
            )}
        </div>
    );

    const renderProcessingStep = () => (
        <div className="flex flex-col items-center justify-center h-full space-y-6">
             <div className="w-16 h-16 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
             <div className="text-center">
                 <h4 className="text-lg font-bold text-text-primary">Analyzing Document...</h4>
                 <p className="text-text-secondary mt-2">Extracting flights and matching personnel...</p>
             </div>
        </div>
    );

    const renderReviewStep = () => (
        <div className="space-y-6">
             <div className="flex justify-between items-center bg-surface-soft p-4 rounded-lg border border-border-default">
                 <div>
                     <h4 className="font-bold text-text-primary">Review Matches</h4>
                     <p className="text-sm text-text-secondary">
                         Found {extractedData.length} flights. Please verify the matched personnel before saving.
                     </p>
                 </div>
                 <button 
                    onClick={handleCommit}
                    disabled={extractedData.filter(d => d.matchedPassengerId).length === 0}
                    className="px-6 py-2 bg-primary text-white font-bold rounded-md hover:bg-primary-dark disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                 >
                     Save {extractedData.filter(d => d.matchedPassengerId).length} Flights
                 </button>
             </div>

             <div className="overflow-x-auto border border-border-default rounded-lg">
                 <table className="min-w-full divide-y divide-border-default">
                     <thead className="bg-surface-soft">
                         <tr>
                             <th className="px-4 py-3 text-left text-xs font-bold text-text-secondary uppercase">Ticket Info</th>
                             <th className="px-4 py-3 text-left text-xs font-bold text-text-secondary uppercase">Extracted Name</th>
                             <th className="px-4 py-3 text-left text-xs font-bold text-text-secondary uppercase">Matched Personnel</th>
                             <th className="px-4 py-3 text-center text-xs font-bold text-text-secondary uppercase">Action</th>
                         </tr>
                     </thead>
                     <tbody className="bg-surface divide-y divide-border-default">
                         {extractedData.map((item, idx) => (
                             <tr key={idx} className="hover:bg-surface-soft/50">
                                 <td className="px-4 py-3 text-sm">
                                     <div className="font-bold text-text-primary">{item.ticketData.departureCity} &rarr; {item.ticketData.arrivalCity}</div>
                                     <div className="text-text-secondary text-xs">{item.ticketData.travelDate} • {item.ticketData.airline}</div>
                                     <div className="text-text-secondary text-xs font-mono">{item.ticketData.ticketNumber}</div>
                                 </td>
                                 <td className="px-4 py-3 text-sm font-medium text-text-primary">
                                     {item.passengerName}
                                 </td>
                                 <td className="px-4 py-3 text-sm">
                                     <select 
                                        className={`w-full p-2 rounded border text-sm focus:ring-1 focus:ring-primary outline-none ${!item.matchedPassengerId ? 'border-warning bg-warning/5' : 'border-border-default bg-background'}`}
                                        value={item.matchedPassengerId || ''}
                                        onChange={(e) => handleMatchChange(idx, e.target.value)}
                                     >
                                         <option value="">-- No Match --</option>
                                         {allPassengers.map(p => (
                                             <option key={p.id} value={p.id}>
                                                 {p.passportData.surname}, {p.passportData.firstNames} ({p.companyId})
                                             </option>
                                         ))}
                                     </select>
                                     {item.matchedPassengerId && (
                                         <div className="mt-1 text-xs text-success flex items-center gap-1">
                                             <CheckCircleIcon className="h-3 w-3" />
                                             Matched
                                         </div>
                                     )}
                                 </td>
                                 <td className="px-4 py-3 text-center">
                                     <button onClick={() => handleRemoveItem(idx)} className="text-danger hover:bg-danger/10 p-2 rounded-full transition-colors" title="Ignore this row">
                                         <XCircleIcon className="h-5 w-5" />
                                     </button>
                                 </td>
                             </tr>
                         ))}
                     </tbody>
                 </table>
                 {extractedData.length === 0 && (
                     <div className="p-8 text-center text-text-secondary">No flights extracted. Try uploading a clearer image.</div>
                 )}
             </div>
        </div>
    );

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Batch Ticket Upload">
            {step === 'upload' && renderUploadStep()}
            {step === 'processing' && renderProcessingStep()}
            {step === 'review' && renderReviewStep()}
            {step === 'saving' && (
                 <div className="flex flex-col items-center justify-center h-full space-y-6">
                    <div className="w-12 h-12 border-4 border-success border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-lg font-bold text-text-primary">Saving Tickets...</p>
               </div>
            )}
        </Modal>
    );
};

