import { FileUploader } from './FileUploader';
import { XMarkIcon, CheckCircleIcon, XCircleIcon, ClipboardDocumentIcon, DocumentTextIcon, CloudArrowUpIcon, PencilIcon } from './icons';

interface BatchTicketUploadModalProps {
