const initialPassportData: PassportData = { type: '', code: '', passportNumber: '', surname: '', firstNames: '', nationality: '', dateOfBirth: '', sex: '', placeOfBirth: '', dateOfIssue: '', authority: '', dateOfExpiry: '' };
const initialGhanaCardData: GhanaCardData = { cardNumber: '', surname: '', firstNames: '', nationality: '', dateOfBirth: '', height: '', documentNumber: '', placeOfIssuance: '', dateOfIssue: '', dateOfExpiry: '' };
const initialContactData: ContactData = { email: '', phone: '' };

const hasData = (obj: object) => {
    // Exclude 'document' and 'id' fields from the check
    return Object.entries(obj).some(([key, value]) => {
        if (key === 'document' || key === 'id') return false;
        if (Array.isArray(value)) return value.length > 0;
        return value && typeof value === 'string' && value.trim() !== '';
    });
};

async function compressDataUrl(dataUrl: string, targetWidth: number, targetHeight: number, quality: number = 0.85): Promise<string> {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => {
            const canvas = document.createElement('canvas');
            canvas.width = targetWidth;
            canvas.height = targetHeight;
            const ctx = canvas.getContext('2d');
            if (!ctx) {
                return reject(new Error('Could not get canvas context'));
            }
            ctx.drawImage(img, 0, 0, targetWidth, targetHeight);
            resolve(canvas.toDataURL('image/jpeg', quality));
        };
        img.onerror = (err) => {
            console.error("Image compression failed:", err);
            reject(new Error('Failed to load image for compression.'));
        };
        img.src = dataUrl;
    });
}


